import json
import os
from datetime import datetime, timezone
from typing import Any, Dict, Optional

from google.cloud import firestore
from google.cloud import pubsub_v1
from google.cloud import storage


PROJECT_ID = os.getenv("GCP_PROJECT") or os.getenv("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.getenv("PUBSUB_TOPIC", "file-processed")
FIRESTORE_COLLECTION = os.getenv("FIRESTORE_COLLECTION", "processed_files")

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher_client = pubsub_v1.PublisherClient()
topic_path = publisher_client.topic_path(PROJECT_ID, PUBSUB_TOPIC) if PROJECT_ID else None


def _safe_decode(data: bytes) -> Optional[str]:
    try:
        return data.decode("utf-8")
    except Exception:
        return None


def _build_document(bucket_name: str, file_name: str, generation: str, size: Optional[int], text_preview: Optional[str]) -> Dict[str, Any]:
    return {
        "bucket": bucket_name,
        "name": file_name,
        "generation": generation,
        "size": size,
        "text_preview": text_preview,
        "processed_at": datetime.now(timezone.utc).isoformat(),
        "project_id": PROJECT_ID,
    }


def process_gcs_event(event, context):
    bucket_name = event["bucket"]
    file_name = event["name"]
    generation = event.get("generation", "")
    size = int(event["size"]) if event.get("size") else None

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    content = blob.download_as_bytes()
    text_preview = _safe_decode(content[:4096])

    document = _build_document(bucket_name, file_name, generation, size, text_preview)

    doc_id = f"{bucket_name}:{file_name}:{generation}".replace("/", "_")
    firestore_client.collection(FIRESTORE_COLLECTION).document(doc_id).set(document)

    if topic_path:
        message = {
            "bucket": bucket_name,
            "name": file_name,
            "generation": generation,
            "size": size,
            "firestore_collection": FIRESTORE_COLLECTION,
            "firestore_document_id": doc_id,
            "processed_at": document["processed_at"],
        }
        publisher_client.publish(
            topic_path,
            json.dumps(message).encode("utf-8"),
            bucket=bucket_name,
            name=file_name,
            generation=str(generation),
        ).result()

    return "OK"